  router.post("/api/auth/register", authLimiter, async (req: Request, res: Response) => {
    try {
      const { email, password, name, ref } = req.body;

      if (!email || !password) {
        return res.status(400).json({ message: "Email and password are required" });
      }

      const existing = await getUserByEmail(email);
      if (existing) {
        return res.status(409).json({ message: "An account with this email already exists" });
      }

      // Generate unique referral code for this new user
      const referralCode = crypto.randomBytes(4).toString("hex").toUpperCase();

      // Validate ref param (someone referred this user)
      let referredBy: string | null = null;
      const refCode = ref || req.query.ref;
      if (refCode && typeof refCode === "string") {
        const referrer = await pool.query(
          "SELECT id FROM users WHERE referral_code = $1 LIMIT 1",
          [refCode.toUpperCase()]
        );
        if (referrer.rows.length > 0) referredBy = refCode.toUpperCase();
      }

      const passwordHash = await bcrypt.hash(password, 12);
      const signupIp =
        (req.headers["x-forwarded-for"] as string)?.split(",")[0]?.trim() ||
        req.socket.remoteAddress ||
        null;
      const user = await createUser({
        email,
        name: name || null,
        passwordHash,
        authProvider: "email",
        referralCode,
        referredBy,
        trialStartedAt: new Date(),
        signupIp,
      } as any);

      const business = await createBusiness(user.id);
      enrollUserInDrip(user.id, email, user.name).catch((e) => console.error("[drip] enroll failed:", e.message));
      sendWelcomeEmail(email, user.name);
      trackEvent(user.id, AnalyticsEvents.ACCOUNT_CREATED, { authProvider: "email" }).catch(() => {});
      trackEvent(user.id, AnalyticsEvents.TRIAL_STARTED, { plan: "free" }).catch(() => {});

      await new Promise<void>((resolve, reject) => {
        req.session.regenerate((err) => (err ? reject(err) : resolve()));
      });
      req.session.userId = user.id;
      await pool.query(`UPDATE users SET last_login_at = NOW() WHERE id = $1`, [user.id]).catch(() => {});

      return res.json({
        user: formatUser(user),
        business: formatBusiness(business),
        needsOnboarding: !business.onboardingComplete,
      });
    } catch (error: any) {
      console.error("Register error:", error);
      return res.status(500).json({ message: "Registration failed" });
    }
  });

  router.post("/api/auth/login", authLimiter, loginFailureLimiter, async (req: Request, res: Response) => {
    try {
      const { email, password } = req.body;

      if (!email || !password) {
        return res.status(400).json({ message: "Email and password are required" });
      }

      // Deactivated demo accounts
      const DEACTIVATED_EMAILS = ["demo@quotepro.com", "todo@quotepro.com"];
      if (DEACTIVATED_EMAILS.includes(email.toLowerCase().trim())) {
        return res.status(401).json({ message: "This account has been deactivated. Please create your own account to continue." });
      }

      const user = await getUserByEmail(email);
      if (!user || !user.passwordHash) {
        return res.status(401).json({ message: "Invalid email or password" });
      }

      const valid = await bcrypt.compare(password, user.passwordHash);
      if (!valid) {
        return res.status(401).json({ message: "Invalid email or password" });
      }

      // Backfill trialStartedAt and referralCode for older accounts
      const backfillData: Record<string, any> = {};
      if (!(user as any).trialStartedAt) backfillData.trialStartedAt = new Date();
      if (!(user as any).referralCode) {
        backfillData.referralCode = crypto.randomBytes(4).toString("hex").toUpperCase();
      }
      if (Object.keys(backfillData).length > 0) {
        await updateUser(user.id, backfillData as any);
        Object.assign(user, backfillData);
      }

      const business = await getBusinessByOwner(user.id);

      await new Promise<void>((resolve, reject) => {
        req.session.regenerate((err) => (err ? reject(err) : resolve()));
      });
      req.session.userId = user.id;
      pool.query(`UPDATE users SET last_login_at = NOW() WHERE id = $1`, [user.id]).catch(() => {});

      return res.json({
        user: formatUser(user),
        business: business ? formatBusiness(business) : null,
        needsOnboarding: !business?.onboardingComplete,
      });
    } catch (error: any) {
      console.error("Login error:", error);
      return res.status(500).json({ message: "Login failed" });
    }
  });

